#include <iostream>
using namespace std;

class Prototype {
public:
    virtual Prototype* clone() const = 0;
    virtual void print() const = 0;
    virtual ~Prototype() = default;
};

class Concrete : public Prototype {
    int value;
public:
    Concrete(int v) : value(v) {}
    Prototype* clone() const override { return new Concrete(*this); }
    void print() const override { cout << value; }
};

int main() {
    Concrete c(42);
    Prototype* copy = c.clone();
    copy->print();
    delete copy;
    return 0;
}

